VALUES
  ('disabled-7c4986e7-moex-00196', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司X2年度綜合損益表中稅前淨利為$70,100，審計人員發現其中包含', '["透過其他綜合損益按公允價值衡量之債務工具投資未實現評 價損失$5,400；", "透過其他綜合損益按公允價值衡量之權益工具投資處分 利益$3,000；", "提前贖回債券利益$22,000；", "X1 年度少計提折舊之追溯 重編影響數$7,500；⑤火災損失$7,000。甲公司X2年度稅前淨利應為："]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00197', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司X2年12月31日期末原料成本為$800,000，重置成本$750,000；期 末在製品1,000單位，成本$231,000，估計至完工尚須投入成本$250,000； 期末製成品2,000單位，成本$1,000,000。每單位產品售價為$500，銷售費 用估計為售價的 8%，正常利潤率估計為售價的 12%，則甲公司 X2 年 12 月31日應報導期末存貨是多少？', '["$1,550,000", "$1,820,000", "$1,880,000", "$1,930,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00198', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司 X1 年期末經盤點確定庫存貨品成本共有$525,000，檢視相關資料', '["目的地交貨之進貨$3,000，X2年1月8日才運達；", "承銷丙公司商品尚未賣出，計有$15,000；", "X1年12月簽訂售後買回合約 ，出售商品給客戶，售價$32,000，成本$12,400，銷售合約給予甲公司一項 買權，甲公司可於 X2年2月按$28,000再買回該商品。試問甲公司X1年 期末正確存貨成本應該為多少？", "$510,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00199', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司於X3年1月3日以$3,500,000取得丙公司40%普通股股權，經評估 具重大影響，同時按股權淨值取得丙公司 50%特別股權益。丙公司 X2 年 底資產負債表上之權益如下：5%累積特別股股本$2,000,000（面額$100，收 回價格$110，積欠兩年股利）；普通股股本$6,000,000（面額$10）；資本公 積$2,000,000；保留盈餘$600,000。假設投資成本與所享有丙公司權益份額 之差額分五年攤銷，X3年度淨利為$600,000，X3年度宣告並發放現金股利 $400,000，X4 年度淨利為$200,000，未發放股利。假設甲公司與丙公司間 並未發生其他交易，則有關前述投資之會計處理，下列何者錯誤？', '["甲公司X3年底對丙公司普通股投資帳戶餘額為$3,660,000", "甲公司X4年底對丙公司普通股投資帳戶餘額為$3,612,000", "甲公司X3年度對丙公司普通股投資之相關投資收益為$156,000", "甲公司X4年度對丙公司普通股投資之相關投資損失為$4,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00200', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', 'X2年1月1日甲公司以$981,190購入乙公司發行之公司債，面額$1,000,000 ，票面利率4%，每年6 月30 日及12 月31 日付息，X3 年12 月31 日到 期，有效利率 5%，甲公司將該債券投資分類為透過其他綜合損益按公允 價值衡量之債券投資。X2 年 12 月 31 日甲公司持有之乙公司公司債帳面 金額為$990,363、公允價值為$985,363，若甲公司於 X3 年 3 月 31 日以 $981,743 加計應收利息出售，另支付手續費$2,000，則甲公司 X3 年認列 處分債券投資損益為何？', '["處分損失$2,000", "處分損失$5,620", "處分損失$11,000", "處分損失$13,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00201', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司於 X2 年底以$100,000（含交易成本）買入乙公司發行之三年期公 司債，面額$100,000，票面利率5%，每年12 月31 日付息一次，分類為 按攤銷後成本衡量之債券投資。有關該公司債的預期信用損失估計如下： 12個月內預期信用損失 存續期間預期信用損失 X2年底 $1,000 $1,800 X3年底 $5,000 $10,500 X4年底 $25,000 $25,000 若X3年底該債券的信用風險已顯著增加，X4年底該債券已自活絡市場中 消失，已達減損的地步。則甲公司於 X2 年底、X3 年底、X4 年底分別應 認列之減損損失金額為何？', '["$1,000、$5,000、$25,000", "$1,800、$10,500、$25,000", "$1,000、$9,500、$14,500", "$1,800、$8,700、$14,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00202', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司 X2 年有關退休金資料如下：期初計畫資產公允價值$600,000，期 初確定給付義務現值$750,000，X2年當期服務成本為$112,500，因退休計 畫精算假設變動產生精算損失$95,000，X2 年底提撥退休基金$124,000， 並支付退休金$107,000。已知折現率為 5%，計畫資產實際報酬為$68,000 ，則甲公司X2年12月31日資產負債表應報導之退休金負債為何？', '["$53,000", "$70,000", "$108,000", "$203,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00203', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', 'X1 年 1 月 1 日甲公司為進行新冠病毒疫苗之研發向衛生福利部申請補助 款，計獲得補助款 $6,000,000。該計畫總研發成本，自X1 年1月1 日起', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00204', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '年內平均發生。疫苗開發完成後，受補助廠商可完全取得開發產品之專 利權，甲公司預計於 X3 年度完成疫苗開發計畫。甲公司於 X2 年 1 月 1 日疫苗第一階段測試失敗而中止研發計畫，違反衛生福利部補助條件，被 要求退還部分補助款$3,000,000。試問上述交易事項對甲公司X2年度本期 淨利之淨影響為何？（不考慮所得稅）', '["增加$500,000", "不受影響", "增加$1,000,000", "減少$1,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00205', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-111-e0b1f2ed', 'sub-disabled-7c4986e7-04', NULL, 'single_choice', '甲公司於 X2 年 1 月 1 日購入一機器設備，成本$546,000，估計耐用年限 6年，殘值$21,000，採年數合計法提列折舊，以成本模式衡量。X4年底該 機器使用方式發生不利之重大變動，經減損測試，估計該機器未來現金流 量現值為$150,000，公允價值為$160,000，處分成本為$2,000，則X4年底 甲公司應認列之減損損失金額為多少？', '["$0", "$6,000", "$13,000", "$21,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
